'use strict';

const discord_js = require('discord.js');
const utils = require('./utils.cjs');

function isMessage(value) {
  if (value instanceof discord_js.Message) {
    return true;
  }
  if (utils.hasConstructor(value) && value.constructor.name === discord_js.Message.name && "id" in value && "toJSON" in value && typeof value.toJSON === "function") {
    const json = value.toJSON();
    return typeof json === "object" && json !== null && "id" in json && json.id === value.id;
  }
  return false;
}

exports.isMessage = isMessage;
